import React from "react";
import FormField from "./FormField";

const COUNTRY_CODES = [
  { value: "+91",  label: "🇮🇳 +91"  },
  { value: "+1",   label: "🇺🇸 +1"   },
  { value: "+44",  label: "🇬🇧 +44"  },
  { value: "+61",  label: "🇦🇺 +61"  },
  { value: "+971", label: "🇦🇪 +971" },
  { value: "+65",  label: "🇸🇬 +65"  },
  { value: "+60",  label: "🇲🇾 +60"  },
];

const GENDERS = [
  { value: "Male",   label: "♂ Male"   },
  { value: "Female", label: "♀ Female" },
  { value: "Other",  label: "⊹ Other"  },
];

const s = {
  phoneRow: { display: "flex", gap: "8px" },
  countrySelect: {
    width: "110px", flexShrink: 0, padding: "10px 6px",
    border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
    fontSize: "13px", background: "var(--input-bg)", color: "var(--text-primary)",
    outline: "none", cursor: "pointer", minHeight: "42px",
  },
  mobileInput: {
    flex: 1, padding: "10px 12px",
    border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
    fontSize: "14px", background: "var(--input-bg)", color: "var(--text-primary)",
    outline: "none", transition: "border .18s, box-shadow .18s", minHeight: "42px",
  },
  mobileError: { border: "1px solid var(--error)" },
  genderRow: { display: "flex", gap: "8px", flexWrap: "wrap" },
  genderBtn: {
    flex: "1 1 70px", padding: "10px 4px", minHeight: "42px",
    border: "1px solid var(--border)", borderRadius: "var(--radius-sm)",
    fontSize: "13px", cursor: "pointer", background: "var(--input-bg)",
    color: "#555", transition: "all .15s", textAlign: "center",
  },
  genderActive: {
    border: "1px solid var(--brand)", background: "var(--brand-light)",
    color: "var(--brand)", fontWeight: 600,
  },
  label:    { display: "block", fontSize: "12px", fontWeight: 600, color: "#444", marginBottom: "5px", letterSpacing: ".3px" },
  field:    { marginBottom: "16px" },
  errorMsg: { fontSize: "11px", color: "var(--error)", marginTop: "4px" },
  btn: {
    width: "100%", padding: "13px", background: "var(--accent)",
    border: "none", borderRadius: "var(--radius-sm)", color: "#fff",
    fontSize: "15px", fontWeight: 700, cursor: "pointer", letterSpacing: ".5px",
    boxShadow: "var(--shadow-btn)", transition: "background .15s", marginTop: "4px",
    minHeight: "48px",
  },
};

export default function Step1PersonalDetails({ fields, errors, updateField, onContinue, loading }) {
  return (
    <div className="fade-slide-in">
      {/* Name row — stacks on mobile via .row-2col CSS */}
      <div className="row-2col">
        <FormField label="First Name" name="firstName" value={fields.firstName}
          onChange={(v) => updateField("firstName", v)} error={errors.firstName}
          placeholder="Rahul" style={{ flex: 1 }} />
        <FormField label="Last Name" name="lastName" value={fields.lastName}
          onChange={(v) => updateField("lastName", v)} error={errors.lastName}
          placeholder="Sharma" style={{ flex: 1 }} />
      </div>

      <FormField label="Email Address" name="email" type="email" value={fields.email}
        onChange={(v) => updateField("email", v)} error={errors.email}
        placeholder="rahul@example.com" autoComplete="email" />

      {/* Mobile */}
      <div style={s.field}>
        <label style={s.label}>Mobile Number</label>
        <div style={s.phoneRow}>
          <select style={s.countrySelect} value={fields.countryCode}
            onChange={(e) => updateField("countryCode", e.target.value)} aria-label="Country code">
            {COUNTRY_CODES.map((c) => <option key={c.value} value={c.value}>{c.label}</option>)}
          </select>
          <input type="tel" value={fields.mobile}
            onChange={(e) => updateField("mobile", e.target.value)}
            placeholder="9876543210"
            style={{ ...s.mobileInput, ...(errors.mobile ? s.mobileError : {}) }}
            aria-label="Mobile number" maxLength={10} />
        </div>
        {errors.mobile && <p style={s.errorMsg}>{errors.mobile}</p>}
      </div>

      <FormField label="Date of Birth" name="dob" type="date" value={fields.dob}
        onChange={(v) => updateField("dob", v)} error={errors.dob} />

      {/* Gender */}
      <div style={s.field}>
        <label style={s.label}>Gender</label>
        <div style={s.genderRow}>
          {GENDERS.map((g) => (
            <button key={g.value} type="button"
              style={{ ...s.genderBtn, ...(fields.gender === g.value ? s.genderActive : {}) }}
              onClick={() => updateField("gender", g.value)}
              aria-pressed={fields.gender === g.value}>
              {g.label}
            </button>
          ))}
        </div>
      </div>

      <button style={s.btn} onClick={onContinue} disabled={loading}
        onMouseEnter={(e) => { e.target.style.background = "var(--accent-dark)"; }}
        onMouseLeave={(e) => { e.target.style.background = "var(--accent)"; }}>
        {loading ? "Checking…" : "Continue →"}
      </button>
    </div>
  );
}
